#!/usr/bin/python3

class Solution:
   def get_element(self, deque: list[int], index: int) -> int:
      if not deque:
         return -1
      if index < 0 or index >= len(deque):
         return -1
      return deque[index]

if __name__ == '__main__':
   from sys import stdin, stdout
   deque = list(map(int, stdin.readline().split()))
   index = int(stdin.readline())
   solution = Solution()
   output = solution.get_element(deque, index)
   if output == -1:
      stdout.write('-1')
   else:
      stdout.write(str(output))

